import { format } from "date-fns";

import { parseLocalDate } from "../../../utils";
import { API } from "../../types";
import { Data, Image } from "./types";

type Config = Data;

const formatDateForApi = (date: string): string => {
  return format(parseLocalDate(date), "yyyy-MM-dd");
};

export async function getPicture(
  data: Config,
  loader: API["loader"],
): Promise<Image> {
  const url = "https://api.nasa.gov/planetary/apod";
  const params = new URLSearchParams();

  if (NASA_API_KEY) {
    params.set("api_key", NASA_API_KEY);
  } else {
    console.log(
      "You must set the NASA_API_KEY environment variable. Falling back to key DEMO_KEY.",
    );
    params.set("api_key", "DEMO_KEY");
  }

  params.set("thumbs", "true");

  if (data.date === "custom" && data.customDate) {
    params.set("date", formatDateForApi(data.customDate));
  }

  loader.push();
  try {
    const res = await fetch(`${url}?${params}`);
    const json = await res.json();
    return json;
  } finally {
    loader.pop();
  }
}
