/** Weather conditions for a point in time */
export interface Conditions {
  timestamp: number;
  temperature: number;
  apparentTemperature: number;
  humidity: number;
  weatherCode: number;
}

/** Daily weather conditions for a date */
export interface DailyConditions {
  timestamp: number;
  temperatureMax: number;
  temperatureMin: number;
  weatherCode: number;
}

/** Find conditions for the current time */
export const findCurrent = (
  conditions: Conditions[],
  now: number,
): Conditions | null =>
  conditions
    .slice()
    .reverse()
    .find((condition) => now >= condition.timestamp) ?? null;

